def _bool_env(name: str, default: bool = False) -> bool:
    val = os.getenv(name)
    if val is None:
        return default
    return val.strip().lower() in ("1", "true", "yes", "y", "on")

APP_NAME = os.getenv("APP_NAME", "flask_app")

USE_MULTIPROC = _bool_env("PROMETHEUS_MULTIPROC", False) or ("PROMETHEUS_MULTIPROC_DIR" in os.environ)
PROM_MPROC_DIR = os.getenv("PROMETHEUS_MULTIPROC_DIR")

registry = CollectorRegistry()
if USE_MULTIPROC:
    if not PROM_MPROC_DIR:
        raise RuntimeError("PROMETHEUS_MULTIPROC is enabled but PROMETHEUS_MULTIPROC_DIR is not set")
    multiprocess.MultiProcessCollector(registry)

REQUESTS_TOTAL = Counter(
    "http_requests_total",
    "Total HTTP requests",
    labelnames=("app", "method", "endpoint", "http_status"),
    registry=registry,
)

IN_FLIGHT = Gauge(
    "http_in_flight_requests",
    "In-flight HTTP requests",
    labelnames=("app",),
    registry=registry,
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    labelnames=("app", "method", "endpoint"),
    buckets=(0.001, 0.0025, 0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10),
    registry=registry,
)

